import { Component, OnInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { EquipsService } from '../../../services/equips.service';  // Supondo que você já tenha esse serviço
import { EquipCategorias } from '../../../models/equip-categorias';  // Modelo de Equipamento


@Component({
  selector: 'app-ataque',
  templateUrl: './ataque.component.html',
  styleUrls: ['./ataque.component.css']
})
export class AtaqueComponent implements OnInit {
  categoria!: string;
  subcategorias: string[] = [];  // A lista de subcategorias que você vai preencher
  equipamentos: EquipCategorias[] = [];

  constructor(
    private route: ActivatedRoute,
    private equipsService: EquipsService
  ) {}

  ngOnInit(): void {
    // Pega a categoria da URL
    this.categoria = this.route.snapshot.paramMap.get('categoria')!;

    // Preencher com as subcategorias de acordo com a categoria
    this.carregarSubcategorias(this.categoria);
  }

  carregarSubcategorias(categoria: string): void {
    // Aqui você pode definir manualmente as subcategorias de acordo com a categoria escolhida
    if (categoria === 'ataque') {
      this.subcategorias = ['armas', 'municao', 'armas-simples', 'armas-marcial', 'armas-corpo-a-corpo', 'armas-a-distancia'];
    } else if (categoria === 'defesa') {
      this.subcategorias = ['Escudos', 'Armaduras'];
    } else if (categoria === 'kits') {
      this.subcategorias = ['equipamento-de-aventura', 'equipamento-padrao', 'kit-de-escalada', 'kit-de-disfarce', 'kit-de-falsificacao', 'kit-de-herborismo', 'kit-de-curandeiro', 'kit-de-refeicao', 'kit-de-venenos'];
    } else if (categoria === 'montaria') {
      this.subcategorias = ['montarias-e-veiculos'];
    } else if (categoria === 'defesa') {
      this.subcategorias = ['Escudos', 'Armaduras'];
    }
    // Adicione mais condições para as outras categorias conforme necessário.
  }

  carregarEquipamentos(subcategoria: string): void {
    // Chama o serviço para obter os equipamentos dessa subcategoria
    this.equipsService.getEquipamentosPorSubcategoria(subcategoria).subscribe((equipamentos) => {
      this.equipamentos = equipamentos;
    });
  }
}
